import{_ as c,$ as v,c as g,a as b,d as h,e,g as o,a2 as s,h as a,f as n,w as u,n as p,b as m,P as w}from"./index.dfc51ec0.js";import{g as y}from"./gameplayGauntlet.688d2006.js";const k={class:"help-container"},f={id:"top",class:"help-header"},_=["src"],C={id:"rewards",class:"help-section"},x={class:"crt-text-gold"},T={class:"help-footer"},B={__name:"gameplayGauntlet",setup(S){const d=v(),l=g(()=>d.query.autoScroll==="true");return(G,t)=>{const r=w,i=b("router-link");return m(),h("div",{class:p(["help-page",{"auto-scroll-mode":o(l)}])},[e("div",k,[e("header",f,[e("img",{src:o(y),alt:"Gameplay Gauntlet",class:"header-logo"},null,8,_),t[0]||(t[0]=e("div",{class:"header-text"},[e("h1",{class:"crt-text-gold"},"\u{1F3C6} GAMEPLAY GAUNTLET"),e("p",{class:"subtitle"},"Vote for the Next Game We Play!")],-1))]),t[6]||(t[6]=s('<section id="basics" class="help-section" data-v-421922eb><h2 class="crt-text-gold" data-v-421922eb>\u{1F4D6} How It Works</h2><div class="content-block" data-v-421922eb><h3 data-v-421922eb>Overview</h3><p data-v-421922eb> Gameplay Gauntlet is a <strong data-v-421922eb>community voting game</strong> where viewers decide which Steam game gets played next! A pool of ~1,500 games scrolls across the stream overlay \u2014 use your <strong data-v-421922eb>vote budget</strong> to back your favorites. The first game to hit <strong data-v-421922eb>11 votes</strong> when the weekly Saturday deadline arrives is declared the <span class="highlight-gold" data-v-421922eb>Community Pick</span> and gets played on stream! </p></div><div class="content-block" data-v-421922eb><h3 data-v-421922eb>\u{1F5F3}\uFE0F Voting Commands</h3><p data-v-421922eb>Each game on the ticker has a unique <strong data-v-421922eb>3-character code</strong> shown on its card. Use it to vote:</p><ul data-v-421922eb><li data-v-421922eb><code data-v-421922eb>!rABC</code> \u2014 Place 1 vote on game with code <code data-v-421922eb>ABC</code></li><li data-v-421922eb><code data-v-421922eb>!rABC 3</code> \u2014 Place 3 votes at once (up to 5 per game)</li><li data-v-421922eb><code data-v-421922eb>!r goTime</code> \u2014 Check your remaining vote budget &amp; cooldown status</li></ul></div></section><div class="pro-tip" data-v-421922eb><strong data-v-421922eb>\u{1F4A1} Strategy Tip:</strong> You can spread votes across multiple games or stack up to 5 on your top pick. Choose wisely \u2014 your budget is limited! </div><section id="budget" class="help-section" data-v-421922eb><h2 class="crt-text-gold" data-v-421922eb>\u{1F4B0} Vote Budget</h2><div class="content-block" data-v-421922eb><h3 data-v-421922eb>\u{1F4CA} Budget System</h3><ul data-v-421922eb><li data-v-421922eb><strong data-v-421922eb>25 votes</strong> \u2014 Your total budget per session</li><li data-v-421922eb><strong data-v-421922eb>5 max per game</strong> \u2014 Can&#39;t dump all votes on one game</li><li data-v-421922eb><strong data-v-421922eb>+1 vote/hour</strong> \u2014 Budget replenishes hourly</li></ul><p data-v-421922eb>Spend your votes wisely! Once you&#39;re out, you&#39;ll need to wait for the hourly replenish.</p></div><div class="content-block" data-v-421922eb><h3 data-v-421922eb>\u23F1\uFE0F Cooldowns</h3><ul data-v-421922eb><li data-v-421922eb><strong data-v-421922eb>7\u201310 min</strong> \u2014 Personal cooldown between votes (randomized)</li><li data-v-421922eb><strong data-v-421922eb>2 min</strong> \u2014 Per-game cooldown (can&#39;t pile onto the same game too fast)</li></ul></div><div class="warning-block" data-v-421922eb><h3 data-v-421922eb>\u26A0\uFE0F Cooldown Penalty</h3><p data-v-421922eb> Trying to vote during your cooldown <strong data-v-421922eb>costs you a vote from your budget</strong> and <strong data-v-421922eb>resets your cooldown</strong> to full! No votes are counted. Don&#39;t spam \u2014 be patient. </p></div><div class="warning-block" data-v-421922eb><h3 data-v-421922eb>\u{1F4C9} Overdraft</h3><p data-v-421922eb> If your budget hits zero (or goes negative), votes won&#39;t count and you won&#39;t earn rewards until the hourly replenish brings you back above zero. </p></div></section>',3)),e("section",C,[e("h2",x,[t[1]||(t[1]=a("\u{1F48E} Rewards & ",-1)),n(r,{currency:"zc",class:"points-inline"}),t[2]||(t[2]=a(" zCubes",-1))]),t[3]||(t[3]=e("div",{class:"content-block"},[e("h3",null,"\u{1F4B0} Reward Breakdown"),e("ul",null,[e("li",null,[e("strong",null,"+33 zC"),a(" \u2014 Per successful vote placed")])]),e("p",null,[a("Votes placed during cooldown or overdraft earn "),e("strong",null,"0 zC"),a(".")])],-1))]),t[7]||(t[7]=s('<section id="winning" class="help-section" data-v-421922eb><h2 class="crt-text-gold" data-v-421922eb>\u{1F3C6} Winning Conditions</h2><div class="content-block" data-v-421922eb><h3 data-v-421922eb>How a Winner Is Declared</h3><ol class="list-disc" data-v-421922eb><li data-v-421922eb>Voting runs all week \u2014 the <strong data-v-421922eb>Saturday deadline</strong> (midnight EST) triggers the winner check</li><li data-v-421922eb>The leading game with <strong data-v-421922eb>11+ votes</strong> from 3+ voters is declared the winner</li><li data-v-421922eb>A <span class="highlight-gold" data-v-421922eb>winner banner</span> is automatically generated and posted to Discord</li><li data-v-421922eb>The winning game gets played on the next stream!</li></ol></div><div class="pro-tip" data-v-421922eb><strong data-v-421922eb>\u{1F4A1} Note:</strong> If no game has reached 11 votes when the timer expires, voting continues until one does. The race isn&#39;t over until someone crosses the finish line! </div></section><section id="overlay" class="help-section" data-v-421922eb><h2 class="crt-text-gold" data-v-421922eb>\u{1F5A5}\uFE0F Reading the Overlay</h2><div class="content-block" data-v-421922eb><h3 data-v-421922eb>Ticker Bar</h3><p data-v-421922eb>The bottom of the stream shows a scrolling ticker with game cards:</p><ul data-v-421922eb><li data-v-421922eb><strong data-v-421922eb>Card size</strong> \u2014 Bigger cards = more votes (visual ranking)</li><li data-v-421922eb><strong data-v-421922eb>3-char code</strong> \u2014 Shown on each card, use with <code data-v-421922eb>!r</code></li><li data-v-421922eb><strong data-v-421922eb>Vote count</strong> \u2014 Current tally displayed on each card</li><li data-v-421922eb><strong data-v-421922eb>Voter avatars</strong> \u2014 Circular Twitch avatars of who voted, with cooldown ring timers</li><li data-v-421922eb><strong data-v-421922eb>\u{1F3C6} separator</strong> \u2014 Shows session time remaining and <code data-v-421922eb>!r goTime</code> hint</li></ul></div><div class="content-block" data-v-421922eb><h3 data-v-421922eb>Masonry Grid</h3><p data-v-421922eb>Above the ticker, a large grid displays all ~1,500 eligible games with Steam artwork. Games with votes are highlighted and promoted to the ticker.</p></div></section>',2)),e("footer",T,[n(i,{to:"/help",class:"back-link"},{default:u(()=>[...t[4]||(t[4]=[a("\u2190 Back to Help Center",-1)])]),_:1}),t[5]||(t[5]=e("p",{class:"crt-text-cyan"},"Need more help? Ask in Twitch chat!",-1))])])],2)}}},A=c(B,[["__scopeId","data-v-421922eb"]]);export{A as default};
